class Solution:
    def winnerSquareGame(self, n: int) -> bool:
        losing = {0}
        winning = set()
        squares = []
        k = 1
        while k * k <= n:
            squares.append(k * k)
            k += 1
        for i in range(1, n + 1):
            is_win = False
            for sq in squares:
                if sq > i:
                    break
                if (i - sq) in losing:
                    is_win = True
                    break
            if is_win:
                winning.add(i)
            else:
                losing.add(i)
        return n in winning

solutions.python:
class Solution:
    def winnerSquareGame(self, n: int) -> bool:
        dp = [False] * (n + 1)
        squares = []
        k = 1
        while k * k <= n:
            squares.append(k * k)
            k += 1
        for i in range(1, n + 1):
            for sq in squares:
                if sq > i:
                    break
                if not dp[i - sq]:
                    dp[i] = True
                    break
        return dp[n]

solutions.javascript:
var winnerSquareGame = function(n) {
    const dp = new Array(n + 1).fill(false);
    const squares = [];
    for (let k = 1; k * k <= n; k++) squares.push(k * k);
    for (let i = 1; i <= n; i++) {
        for (const sq of squares) {
            if (sq > i) break;
            if (!dp[i - sq]) {
                dp[i] = true;
                break;
            }
        }
    }
    return dp[n];
};
